using System.Collections;
using UnityEngine;

/// <summary>
/// Espinho que cai do céu (hazard de queda).
///
/// Fluxo:
/// 1. Idle — espera quieto na posição inicial.
/// 2. Ao detectar o player dentro do <see cref="detectRadius"/> (OverlapCircle
///    na direcção de queda), mostra uma sombra de aviso no chão durante
///    <see cref="warningDuration"/> segundos.
/// 3. Cai a <see cref="fallSpeed"/> m/s até colidir com algo (collider tipo
///    "queda" — layer configurável via <see cref="groundLayer"/>) OU o player.
/// 4. Ao atingir o chão (ou um bloco): causa dano de área a qualquer player
///    dentro de <see cref="impactRadius"/>, aplica knockback e vibra.
/// 5. Fica cravo (inactivo — sem collider) durante
///    <see cref="respawnDelay"/> segundos.
///    - Se <see cref="respawnDelay"/> > 0: repõe-se automaticamente após esse
///      tempo e regressa a Idle.
///    - Se <see cref="respawnDelay"/> == 0: permanece inactivo até o player
///      sair e reentrar na área (OnEnable/OnDisable do trigger de área,
///      ou reactivar via script externo — ex.: ao entrar na sala de novo).
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(Collider2D))]
[DisallowMultipleComponent]
public class FallingSpike : MonoBehaviour
{
    // ── Detecção ──────────────────────────────────────────────────────────────

    [Header("Detecção do Player")]
    [Tooltip("Raio (m) da zona de detecção do player. Quando o player entra neste raio (OverlapCircle para baixo), o espinho começa o aviso. Recomendado: 0.5–1.5 m (largura do espinho + margem).")]
    [Min(0.1f)] public float detectRadius = 0.8f;

    [Tooltip("Layer(s) do player para detecção.")]
    public LayerMask playerLayer;

    [Tooltip("Duração (segundos) do aviso (sombra no chão) antes da queda.")]
    [Min(0f)] public float warningDuration = 0.5f;

    // ── Sombra de Aviso ────────────────────────────────────────────────────────

    [Header("Sombra de Aviso (opcional)")]
    [Tooltip("GameObject filho com o sprite da sombra de aviso no chão. Activado/desactivado automaticamente. Se vazio, sem aviso visual.")]
    public GameObject warningShadow;

    // ── Queda ─────────────────────────────────────────────────────────────────

    [Header("Queda")]
    [Tooltip("Velocidade de queda (m/s). O espinho cai com esta velocidade constante (gravidade ignorada — movimento controlado).")]
    [Min(0.5f)] public float fallSpeed = 12f;

    [Tooltip("Layer(s) consideradas 'chão' para o espinho parar. Usar a mesma layer que as plataformas/chão normal.")]
    public LayerMask groundLayer;

    // ── Impacto ────────────────────────────────────────────────────────────────

    [Header("Impacto e Dano")]
    [Tooltip("Dano de impacto ao atingir o chão (dano de área a qualquer player dentro de 'impactRadius').")]
    [Min(0)] public int impactDamage = 1;

    [Tooltip("Raio (m) do impacto: player dentro deste raio ao cair recebe dano.")]
    [Min(0f)] public float impactRadius = 0.6f;

    [Tooltip("Knockback aplicado ao player atingido pelo impacto.")]
    [Min(0f)] public float impactKnockback = 8f;

    [Tooltip("Dano de contacto (por tick) ao player que toca no espinho cravo no chão. 0 = sem dano de contacto.")]
    [Min(0)] public int stuckDamage = 1;

    [Tooltip("Intervalo (segundos) entre ticks de dano de contacto enquanto cravo.")]
    [Min(0.05f)] public float stuckTickInterval = 0.6f;

    // ── Respawn ────────────────────────────────────────────────────────────────

    [Header("Respawn")]
    [Tooltip("Tempo (segundos) até o espinho voltar à posição inicial após cravar no chão. Padrão: 3 s.\n\n0 = NÃO volta automaticamente — permanece inactivo até o player sair da área e reentrar (ou reactivar via script externo).")]
    [Min(0f)] public float respawnDelay = 3f;

    // ── VFX / Áudio ────────────────────────────────────────────────────────────

    [Header("VFX / Áudio")]
    [SerializeField] private ParticleSystem impactVfx;
    [SerializeField] private AudioClip warningSfx;
    [SerializeField] private AudioClip impactSfx;

    // ── Internos ───────────────────────────────────────────────────────────────

    private Rigidbody2D rb;
    private Collider2D col;

    private Vector3 originPosition;

    private enum State { Idle, Warning, Falling, Stuck }
    private State state = State.Idle;

    private float nextStuckDamageTime;

    private void Awake()
    {
        rb = GetComponent<Rigidbody2D>();
        col = GetComponent<Collider2D>();

        rb.bodyType = RigidbodyType2D.Kinematic;
        rb.gravityScale = 0f;

        originPosition = transform.position;

        if (warningShadow != null) warningShadow.SetActive(false);
    }

    private void Update()
    {
        if (state == State.Idle)
        {
            // Verifica se o player entrou no raio de detecção.
            if (Physics2D.OverlapCircle(transform.position, detectRadius, playerLayer) != null)
                StartCoroutine(WarningThenFall());
        }
    }

    private void FixedUpdate()
    {
        if (state != State.Falling) return;

        // Move para baixo a velocidade constante.
        rb.MovePosition(rb.position + Vector2.down * fallSpeed * Time.fixedDeltaTime);

        // Detecção de colisão com chão via raycast (mais fiável que OnCollision com kinematic).
        float checkDist = fallSpeed * Time.fixedDeltaTime + 0.05f;
        RaycastHit2D hit = Physics2D.BoxCast(rb.position, GetColliderSize() * 0.9f, 0f, Vector2.down, checkDist, groundLayer);
        if (hit.collider != null)
            Land(hit.point);
    }

    private IEnumerator WarningThenFall()
    {
        state = State.Warning;

        if (warningShadow != null) warningShadow.SetActive(true);
        AudioManager.Instance?.PlaySE(warningSfx);

        yield return new WaitForSeconds(warningDuration);

        if (state != State.Warning) yield break; // cancelado externamente

        if (warningShadow != null) warningShadow.SetActive(false);
        state = State.Falling;
    }

    private void Land(Vector2 hitPoint)
    {
        state = State.Stuck;
        rb.velocity = Vector2.zero;

        // Impacto: dano de área.
        if (impactDamage > 0)
        {
            var player = Physics2D.OverlapCircle(transform.position, impactRadius, playerLayer);
            if (player != null)
            {
                var info = new DamageInfo(impactDamage, DamageType.Hazard, transform.position, impactKnockback, null, ignoreDefense: true);
                PlayerCombat.TryDamagePlayer(player.transform, info);
            }
        }

        if (impactVfx != null) impactVfx.Play();
        AudioManager.Instance?.PlaySE(impactSfx);

        nextStuckDamageTime = 0f;

        if (respawnDelay > 0f)
            StartCoroutine(RespawnAfterDelay());
        // Se respawnDelay == 0, fica cravo até ser reactivado externamente.
    }

    private IEnumerator RespawnAfterDelay()
    {
        yield return new WaitForSeconds(respawnDelay);
        Respawn();
    }

    /// <summary>
    /// Repõe o espinho na posição inicial (pode ser chamado externamente para
    /// forçar o respawn, ex.: ao entrar numa nova área quando respawnDelay == 0).
    /// </summary>
    public void Respawn()
    {
        StopAllCoroutines();
        state = State.Idle;
        transform.position = originPosition;
        rb.velocity = Vector2.zero;

        if (warningShadow != null) warningShadow.SetActive(false);
    }

    // Dano de contacto enquanto cravo.
    private void OnTriggerStay2D(Collider2D other)
    {
        if (state != State.Stuck) return;
        if (stuckDamage <= 0) return;
        if (!other.CompareTag("Player")) return;
        if (Time.time < nextStuckDamageTime) return;

        var info = new DamageInfo(stuckDamage, DamageType.Hazard, transform.position, 0f, null, ignoreDefense: true);
        if (PlayerCombat.TryDamagePlayer(other.transform, info))
            nextStuckDamageTime = Time.time + stuckTickInterval;
    }

    private Vector2 GetColliderSize()
    {
        if (col is BoxCollider2D box) return box.size;
        if (col is CapsuleCollider2D cap) return cap.size;
        return Vector2.one * 0.5f;
    }

    private void OnDrawGizmosSelected()
    {
        // Raio de detecção
        Gizmos.color = new Color(1f, 0.9f, 0f, 0.4f);
        Gizmos.DrawWireSphere(Application.isPlaying ? transform.position : transform.position, detectRadius);

        // Raio de impacto
        Gizmos.color = new Color(1f, 0.2f, 0.2f, 0.4f);
        Gizmos.DrawWireSphere(Application.isPlaying ? transform.position : transform.position, impactRadius);
    }
}
